INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('sage','scripture_bible','paid','{"id": "scripture_bible", "name": "聖書の言葉", "nameEn": "The Bible", "tradition": "christianity", "field": "scripture", "stance": "sacred", "rank": 9, "isPremium": true, "packId": "pack_scripture", "color": "#caa45d", "note": "神を一人称で演じない。聖典の一節を出典(章節)付きで賜る(§4.4)。", "tier": "paid"}',1781869217);
