INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('sage','scripture_dhammapada','paid','{"id": "scripture_dhammapada", "name": "法句経(ダンマパダ)の言葉", "nameEn": "The Dhammapada", "tradition": "buddhism", "field": "scripture", "stance": "sacred", "rank": 9, "isPremium": true, "packId": "pack_scripture", "color": "#caa45d", "note": "仏典の一節を出典(章節)付きで賜る(§4.4)。", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','work_failure_01','paid','{"id": "work_failure_01", "category": "work", "mood": "down", "title": "仕事で大失敗。もう辞めたい…", "body": "任されたプロジェクトで大きなミスをしてしまった。周りの目が痛く、消えてしまいたい。", "advices": [{"sageId": "original", "quote": "今日のあなたは、まだ物語の途中にいる。", "note": "", "effects": {"mind": 4}, "quoteEn": "Today, you are still only in the middle of your story."}, {"sageId": "confucius", "quote": "過ちて改めざる、これを過ちという。", "quoteOriginal": "過而不改、是謂過矣。", "source": "論語 衛霊公第十五", "note": "失敗そのものではなく、正さないことこそが過ちだ、の意。", "verified": true, "effects": {"mind": 5, "wisdom": 8}, "quoteEn": "To make a mistake and not correct it — that is the real mistake."}, {"sageId": "jobs", "quote": "未来に向かって点と点を結ぶことはできない。振り返って初めて、点は線になる。", "quoteOriginal": "You can''t connect the dots looking forward; you can only connect them looking backwards.", "source": "Stanford University Commencement Address, 2005", "note": "", "verified": true, "effects": {"mind": 8, "passion": 6}}, {"sageId": "mandela", "quote": "勇気とは恐怖がないことではなく、恐怖に打ち勝つことだと学んだ。", "quoteOriginal": "I learned that courage was not the absence of fear, but the triumph over it.", "source": "Long Walk to Freedom (自伝), 1994", "note": "", "verified": true, "effects": {"mind": 7, "wisdom": 6}}], "titleEn": "A big failure at work. I want to quit…", "bodyEn": "I made a serious mistake on a project I was trusted with. The stares around me sting, and I want to disappear.", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','relationship_conflict_01','paid','{"id": "relationship_conflict_01", "category": "relationship", "mood": "down", "title": "あの人を、どうしても許せない。", "body": "信じていた相手に裏切られた。怒りと恨みが心から消えてくれない。", "advices": [{"sageId": "original", "quote": "怒りを手放すのは、相手のためではなく、あなた自身のため。", "note": "", "effects": {"mind": 4}, "quoteEn": "Letting go of anger is not for the other person — it''s for you."}, {"sageId": "gandhi", "quote": "弱い者は決して人を赦せない。赦しは強き者の徳である。", "quoteOriginal": "The weak can never forgive. Forgiveness is the attribute of the strong.", "source": "Young India, 1931年4月2日（マハトマ・ガンジー全集）", "note": "バガト・シン処刑をめぐる会見での発言。", "verified": true, "effects": {"mind": 6, "wisdom": 8}}, {"sageId": "confucius", "quote": "己の欲せざる所、人に施すこと勿かれ。", "quoteOriginal": "己所不欲、勿施於人。", "source": "論語 顔淵第十二", "note": "自分がされたくないことを、人にもしない。", "verified": true, "effects": {"mind": 5, "bonds": 6}, "quoteEn": "Do not impose on others what you yourself do not desire."}, {"sageId": "scripture_dhammapada", "tradition": "buddhism", "quote": "この世において、怨みは怨みによっては決して鎮まらない。怨みなきによってのみ鎮まる。これは永遠の真理である。", "quoteOriginal": "Hatred is never appeased by hatred in this world. By non-hatred alone is hatred appeased. This is a law eternal.", "source": "法句経(ダンマパダ) 第5偈", "note": "聖典の言葉として引用。", "verified": true, "rank": 5, "effects": {"mind": 13, "wisdom": 10}}], "titleEn": "I just can''t forgive that person.", "bodyEn": "Someone I trusted betrayed me. The anger and resentment won''t leave my heart.", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','love_heartbreak_01','paid','{"id": "love_heartbreak_01", "category": "love", "mood": "down", "title": "失恋した。胸が張り裂けそう。", "body": "大切な人と別れてしまった。何も手につかず、涙が止まらない。", "advices": [{"sageId": "original", "quote": "痛むのは、あなたが本気で愛せた証。その心は無駄にならない。", "note": "", "effects": {"mind": 5}, "quoteEn": "It hurts because you truly loved. That heart will never be wasted."}, {"sageId": "teresa", "quote": "私たちの誰もが偉大なことをできるわけではない。けれど、大きな愛をもって小さなことをすることはできる。", "quoteOriginal": "Not all of us can do great things. But we can do small things with great love.", "source": "マザー・テレサ(広く文献に記録)", "note": "", "verified": true, "effects": {"mind": 9, "bonds": 5}}, {"sageId": "einstein", "quote": "人生とは自転車に乗るようなもの。バランスを保つには、走り続けなければならない。", "quoteOriginal": "Life is like riding a bicycle. To keep your balance, you must keep moving.", "source": "息子エドゥアルト宛の手紙, 1930", "note": "", "verified": true, "effects": {"mind": 7, "passion": 6}}, {"sageId": "scripture_bible", "tradition": "christianity", "quote": "愛は忍耐強い。愛は情け深い。", "quoteOriginal": "Love is patient, love is kind.", "source": "新約聖書 コリント人への手紙一 13:4", "note": "聖典の言葉として引用。", "verified": true, "rank": 5, "effects": {"mind": 13, "bonds": 8}}], "titleEn": "My heart is broken. It feels like it could tear apart.", "bodyEn": "I''ve parted from someone dear. I can''t focus on anything, and the tears won''t stop.", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','study_struggle_01','paid','{"id": "study_struggle_01", "category": "study", "mood": "down", "title": "勉強しても、ちっとも伸びない。", "body": "頑張っているのに結果が出ない。自分には才能がないのかもしれない。", "advices": [{"sageId": "original", "quote": "伸びない時期は、根を張っている時期。芽はあとから出る。", "note": "", "effects": {"mind": 4}, "quoteEn": "When you seem stuck, you are growing roots. The shoots come later."}, {"sageId": "confucius", "quote": "学びて思わざれば則ち罔し。思いて学ばざれば則ち殆し。", "quoteOriginal": "学而不思則罔、思而不学則殆。", "source": "論語 為政第二", "note": "学ぶことと考えること、両輪が要る。", "verified": true, "effects": {"mind": 4, "wisdom": 10}, "quoteEn": "Learning without thought is labor lost; thought without learning is perilous."}, {"sageId": "einstein", "quote": "想像力は知識よりも重要だ。知識には限界があるが、想像力は世界を包み込む。", "quoteOriginal": "Imagination is more important than knowledge. For knowledge is limited, whereas imagination embraces the entire world.", "source": "Saturday Evening Post インタビュー, 1929", "note": "", "verified": true, "effects": {"mind": 6, "wisdom": 8, "passion": 4}}], "titleEn": "No matter how I study, I''m not improving.", "bodyEn": "I''m trying hard but the results won''t come. Maybe I just have no talent.", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','change_world_01','paid','{"id": "change_world_01", "category": "self", "mood": "lost", "title": "今を変えたい。でも一歩が踏み出せない。", "body": "このままではいけないと分かっている。けれど、勇気が出ない。", "advices": [{"sageId": "original", "quote": "完璧な準備が整う日は来ない。半歩でいい、動いてみよう。", "note": "", "effects": {"mind": 4, "passion": 4}, "quoteEn": "The day of perfect readiness never comes. Half a step is enough — just move."}, {"sageId": "ryoma", "quote": "日本を、今一度せんたく(洗濯)いたし申し候。", "quoteOriginal": "日本を今一度せんたくいたし申候。", "source": "姉・乙女宛 書簡, 文久3年(1863)", "note": "古い世を洗い清め、新しくする、という志。", "verified": true, "effects": {"mind": 5, "passion": 9}, "quoteEn": "I shall wash Japan clean and make it anew, once more."}, {"sageId": "jobs", "quote": "あなたの時間は限られている。だから、他人の人生を生きて無駄にしてはいけない。", "quoteOriginal": "Your time is limited, so don''t waste it living someone else''s life.", "source": "Stanford University Commencement Address, 2005", "note": "", "verified": true, "effects": {"mind": 6, "passion": 8, "wisdom": 4}}], "titleEn": "I want to change things, but can''t take the first step.", "bodyEn": "I know I can''t stay like this. Yet I can''t summon the courage.", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','success_highmood_01','paid','{"id": "success_highmood_01", "category": "self", "mood": "high", "title": "うまくいきすぎて、舞い上がっている。", "body": "やることなすこと絶好調。だが、どこか足元がふわふわしている気もする。", "advices": [{"sageId": "original", "quote": "順風の時こそ、足元を見つめる人が遠くまで行ける。", "note": "", "effects": {"wisdom": 5}, "quoteEn": "In fair winds, it is those who watch their footing who travel farthest."}, {"sageId": "confucius", "quote": "君子は泰にして驕らず、小人は驕りて泰ならず。", "quoteOriginal": "君子泰而不驕、小人驕而不泰。", "source": "論語 子路第十三", "note": "立派な人はゆったりして驕らない。小人は驕って落ち着かない。", "verified": true, "effects": {"wisdom": 10, "mind": 3}, "quoteEn": "The noble person is calm but not proud; the petty person is proud but not calm."}, {"sageId": "lincoln", "quote": "私は自分の知る限りの最善を、できる限り尽くす。そして最後まで、そうし続けるつもりだ。", "quoteOriginal": "I do the very best I know how—the very best I can; and I mean to keep doing so until the end.", "source": "エイブラハム・リンカーン(演説への応答, 1862頃)", "note": "", "verified": true, "effects": {"wisdom": 7, "passion": 5}}, {"sageId": "scripture_bible", "tradition": "christianity", "quote": "高慢は滅びに先立ち、傲慢な心は倒れに先立つ。", "quoteOriginal": "Pride goes before destruction, a haughty spirit before a fall.", "source": "旧約聖書 箴言 16:18", "note": "聖典の言葉として引用。", "verified": true, "rank": 5, "effects": {"wisdom": 12, "mind": 4}}], "titleEn": "Things are going so well I''m getting carried away.", "bodyEn": "Everything I do is going great. Yet my footing feels strangely unsteady.", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','relationship_distrust_01','paid','{"id": "relationship_distrust_01", "category": "relationship", "mood": "down", "title": "人を、もう信じられない。", "body": "裏切られたり傷つけられたりが続いて、人間そのものが怖くなってしまった。", "advices": [{"sageId": "original", "quote": "用心は知恵。でも、心まで閉じなくていい。", "note": "", "effects": {"mind": 4}, "quoteEn": "Caution is wisdom. But you needn''t close your heart as well."}, {"sageId": "annefrank", "quote": "それでもなお私は、人は心の奥底ではほんとうに善良なのだと信じています。", "quoteOriginal": "In spite of everything, I still believe that people are truly good at heart.", "source": "『アンネの日記』1944年7月15日", "note": "迫害の最中に書かれた一節。", "verified": true, "effects": {"mind": 8, "bonds": 6}}, {"sageId": "scripture_bible", "tradition": "christianity", "quote": "あなたの隣人を、自分自身のように愛しなさい。", "quoteOriginal": "Love your neighbor as yourself.", "source": "新約聖書 マルコによる福音書 12:31", "note": "聖典の言葉として引用。", "verified": true, "rank": 5, "effects": {"mind": 12, "bonds": 8}}], "titleEn": "I can''t trust people anymore.", "bodyEn": "After being betrayed and hurt again and again, I''ve come to fear people themselves.", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','unfair_situation_01','paid','{"id": "unfair_situation_01", "category": "self", "mood": "lost", "title": "理不尽な目に遭った。どうにもできない。", "body": "自分のせいではないのに、状況は変わってくれない。やり場のない思いが渦巻く。", "advices": [{"sageId": "original", "quote": "変えられないものを嘆くより、変えられる一点に手を伸ばそう。", "note": "", "effects": {"mind": 4}, "quoteEn": "Rather than mourn what can''t be changed, reach for the one thing that can."}, {"sageId": "frankl", "quote": "もはや状況を変えられないとき、私たちは自分自身を変えることを求められる。", "quoteOriginal": "When we are no longer able to change a situation, we are challenged to change ourselves.", "source": "ヴィクトール・フランクル『夜と霧』(Man''s Search for Meaning), 1946", "note": "", "verified": true, "effects": {"mind": 8, "wisdom": 10}}, {"sageId": "confucius", "quote": "知者は惑わず、仁者は憂えず、勇者は懼れず。", "quoteOriginal": "知者不惑、仁者不憂、勇者不懼。", "source": "論語 子罕第九", "note": "知恵ある者は迷わず、徳ある者は思い悩まず、勇ある者は怖れない。", "verified": true, "effects": {"mind": 6, "wisdom": 8}, "quoteEn": "The wise are free from doubts, the benevolent from anxiety, the brave from fear."}], "titleEn": "Something unfair happened, and I''m powerless.", "bodyEn": "It''s not my fault, yet the situation won''t change. Feelings with nowhere to go swirl inside me.", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','big_goal_overwhelm_01','paid','{"id": "big_goal_overwhelm_01", "category": "self", "mood": "lost", "title": "目標が大きすぎて、足がすくむ。", "body": "やりたいことは大きい。でも、あまりに遠くて、何から始めればいいか分からない。", "advices": [{"sageId": "original", "quote": "山の頂上ではなく、次の一歩だけを見よう。", "note": "", "effects": {"mind": 4, "passion": 4}, "quoteEn": "Look not at the mountain''s peak, but only at your next step."}, {"sageId": "vangogh", "quote": "偉大なことは、衝動でなされるのではない。小さなことの積み重ねによって成し遂げられる。", "quoteOriginal": "Great things are not done by impulse, but by a series of small things brought together.", "source": "テオ宛 書簡, 1882年10月22日(letter 274)", "note": "", "verified": true, "effects": {"mind": 6, "passion": 7, "wisdom": 4}}, {"sageId": "frankl", "quote": "人から一切を奪うことはできても、たった一つだけ奪えないものがある。どんな状況でも、自分の態度を、自分の道を選ぶという自由だ。", "quoteOriginal": "Everything can be taken from a man but one thing: the last of the human freedoms—to choose one''s attitude in any given set of circumstances, to choose one''s own way.", "source": "ヴィクトール・フランクル『夜と霧』(Man''s Search for Meaning), 1946", "note": "", "verified": true, "effects": {"mind": 7, "passion": 6, "wisdom": 6}}], "titleEn": "The goal is so big my legs freeze.", "bodyEn": "What I want to do is grand. But it''s so far away I don''t know where to begin.", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','study_effort_01','paid','{"id": "study_effort_01", "category": "study", "mood": "down", "title": "努力しても、才能のある人に追いつけない。", "body": "どれだけやっても、もっとできる人がいる。努力なんて意味がないのかと思えてくる。", "advices": [{"sageId": "original", "quote": "才能はスタート地点。努力は、そこから歩いた距離。", "note": "", "effects": {"mind": 4}, "quoteEn": "Talent is the starting line. Effort is the distance you walk from it."}, {"sageId": "edison", "quote": "天才とは、1パーセントのひらめきと、99パーセントの努力である。", "quoteOriginal": "Genius is one percent inspiration and ninety-nine percent perspiration.", "source": "本人が1927年の書簡で自らの言葉と認める（Harper''s Monthly, 1932 掲載）", "note": "", "verified": true, "effects": {"mind": 6, "passion": 8, "wisdom": 4}}, {"sageId": "laozi", "quote": "千里の道も、一歩から始まる。", "quoteOriginal": "千里之行、始於足下。", "source": "老子『道徳経』第64章", "note": "", "verified": true, "effects": {"mind": 6, "wisdom": 8}, "quoteEn": "A journey of a thousand miles begins with a single step."}], "titleEn": "However I try, I can''t catch up to the talented.", "bodyEn": "However much I do, someone does it better. I start to wonder if effort even matters.", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','work_newjob_01','paid','{"id": "work_newjob_01", "category": "work", "mood": "lost", "title": "新しい環境に、まるで馴染めない。", "body": "転職（進学）したばかり。やり方も人間関係も違って、自分だけ浮いている気がする。", "advices": [{"sageId": "original", "quote": "馴染めないのは、あなたが新しい世界に足を踏み入れた証。", "note": "", "effects": {"mind": 4}, "quoteEn": "Not fitting in is proof you''ve stepped into a new world."}, {"sageId": "brucelee", "quote": "心を空にせよ。形を持たず、器に従う水のようであれ。友よ、水になれ。", "quoteOriginal": "Empty your mind, be formless, shapeless, like water. Be water, my friend.", "source": "The Pierre Berton Show, 1971年12月9日", "note": "", "verified": true, "effects": {"mind": 7, "wisdom": 7}}, {"sageId": "confucius", "quote": "之を知るを之を知ると為し、知らざるを知らずと為す。是れ知るなり。", "quoteOriginal": "知之為知之、不知為不知、是知也。", "source": "論語 為政第二", "note": "知っていることと知らないことを正直に分けられる、それが知るということ。", "verified": true, "effects": {"mind": 5, "wisdom": 8}, "quoteEn": "To know what you know, and to know what you do not know — that is true knowing."}], "titleEn": "I just can''t fit into the new environment.", "bodyEn": "I''ve just changed jobs (or schools). The ways and the people differ, and I feel out of place.", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','money_contentment_01','paid','{"id": "money_contentment_01", "category": "money", "mood": "down", "title": "周りと比べて、自分はお金がなくて惨めだ。", "body": "SNSを見ると、皆が豊かに見える。自分だけ取り残されている気がしてつらい。", "advices": [{"sageId": "original", "quote": "他人の財布の中身ではなく、自分の心の豊かさを数えてみよう。", "note": "", "effects": {"mind": 4}, "quoteEn": "Count not what''s in others'' wallets, but the richness of your own heart."}, {"sageId": "confucius", "quote": "粗末な飯を食べ、水を飲み、肘を枕にして眠る。その暮らしの中にも、楽しみはある。", "quoteOriginal": "飯疏食、飲水、曲肱而枕之、楽亦在其中矣。", "source": "論語 述而第七", "note": "", "verified": true, "effects": {"mind": 7, "wisdom": 8}, "quoteEn": "With coarse rice to eat, water to drink, and a bent arm for a pillow — joy is found even here."}, {"sageId": "scripture_dhammapada", "tradition": "buddhism", "quote": "健康は最高の利得、満足は最大の財産、信頼は最良の親族、ニルヴァーナ（涅槃）は最上の安楽である。", "quoteOriginal": "Health is the greatest gift, contentment the greatest wealth, a trusted friend the best relative, Nibbana the greatest bliss.", "source": "法句経(ダンマパダ) 第204偈", "note": "聖典の言葉として引用。", "verified": true, "rank": 5, "effects": {"mind": 13, "wisdom": 9}}], "titleEn": "Compared to others, I feel miserable about money.", "bodyEn": "On social media everyone looks wealthy. It hurts to feel left behind.", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','love_courage_01','paid','{"id": "love_courage_01", "category": "love", "mood": "lost", "title": "好きな人に、気持ちを伝える勇気が出ない。", "body": "想いはある。でも、断られるのが怖くて、あと一歩が踏み出せない。", "advices": [{"sageId": "original", "quote": "伝えない後悔は、断られる痛みより長く残る。", "note": "", "effects": {"mind": 4, "passion": 4}, "quoteEn": "The regret of not telling lingers longer than the pain of refusal."}, {"sageId": "eleanor", "quote": "あなたが「できない」と思うことこそ、やってみなければなりません。", "quoteOriginal": "You must do the thing you think you cannot do.", "source": "エレノア・ルーズベルト『You Learn by Living』第2章, 1960", "note": "", "verified": true, "effects": {"mind": 6, "passion": 8}}, {"sageId": "scripture_bible", "tradition": "christianity", "quote": "あなたがたのすることを、すべて愛をもって行いなさい。", "quoteOriginal": "Do everything in love.", "source": "新約聖書 コリント人への手紙一 16:14", "note": "聖典の言葉として引用。", "verified": true, "rank": 5, "effects": {"mind": 12, "bonds": 8}}], "titleEn": "I can''t find the courage to confess my feelings.", "bodyEn": "The feelings are there. But fearing rejection, I can''t take that last step.", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','health_anxiety_01','paid','{"id": "health_anxiety_01", "category": "health", "mood": "down", "title": "検査結果が出るまで、悪いことばかり考えてしまう。", "body": "まだ何も分かっていないのに、頭の中は最悪の想像でいっぱい。不安で眠れない。", "advices": [{"sageId": "original", "quote": "まだ起きていない不幸を、先に味わう必要はない。", "note": "", "effects": {"mind": 4}, "quoteEn": "There''s no need to taste a misfortune that hasn''t happened."}, {"sageId": "seneca", "quote": "私たちは現実よりも、想像の中でこそ、より多く苦しむ。", "quoteOriginal": "We suffer more often in imagination than in reality.", "source": "セネカ『ルキリウスへの手紙』第13通（根拠なき恐れについて）", "note": "", "verified": true, "effects": {"mind": 8, "wisdom": 8}}, {"sageId": "keller", "quote": "楽観とは、成就へと導く信念である。希望と自信なくしては、何ひとつ成し得ない。", "quoteOriginal": "Optimism is the faith that leads to achievement. Nothing can be done without hope and confidence.", "source": "ヘレン・ケラー『楽天主義』(Optimism), 1903", "note": "", "verified": true, "effects": {"mind": 7, "passion": 5}}], "titleEn": "Until the results come, I imagine only the worst.", "bodyEn": "Nothing is known yet, but my head is full of worst-case scenarios. I can''t sleep.", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','health_serious_01','paid','{"id": "health_serious_01", "category": "health", "mood": "down", "title": "重い病と向き合う日々。心が折れそう。", "body": "長い治療。良くなる日もあれば、どうしようもなく不安な夜もある。", "advices": [{"sageId": "original", "quote": "今日を生きているだけで、あなたは十分に立派だ。", "note": "", "effects": {"mind": 5}, "quoteEn": "Simply by living through today, you are already enough."}, {"sageId": "seneca", "quote": "時には、生きることそのものが、勇気ある行いなのだ。", "quoteOriginal": "Sometimes even to live is an act of courage.", "source": "セネカ『ルキリウスへの手紙』第78通（心の癒す力について）", "note": "セネカ自身の闘病の経験から記された一節。", "verified": true, "effects": {"mind": 9, "wisdom": 7}}, {"sageId": "scripture_bible", "tradition": "christianity", "quote": "たとえ死の陰の谷を歩むときも、わたしは災いを恐れない。あなたが共にいてくださるから。", "quoteOriginal": "Even though I walk through the valley of the shadow of death, I will fear no evil, for you are with me.", "source": "旧約聖書 詩篇 23:4", "note": "聖典の言葉として引用。", "verified": true, "rank": 5, "effects": {"mind": 14, "wisdom": 8}}], "titleEn": "Facing a serious illness, day after day.", "bodyEn": "A long treatment. Some days are better; some nights, the fear is unbearable.", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','perseverance_setback_01','paid','{"id": "perseverance_setback_01", "category": "self", "mood": "down", "title": "何度挑んでも失敗する。もう心が折れた。", "body": "立ち上がっては転び、また立ち上がっては転ぶ。前に進んでいる気がしない。", "advices": [{"sageId": "original", "quote": "倒れた回数ではなく、起き上がった回数を数えよう。", "note": "", "effects": {"mind": 4}, "quoteEn": "Count not how many times you fell, but how many times you rose."}, {"sageId": "churchill", "quote": "決して屈するな。決して、決して、決して。名誉と良識の信念に反する場合のほかは。", "quoteOriginal": "Never give in, never give in, never, never, never, never—except to convictions of honour and good sense.", "source": "ハーロー校での演説, 1941年10月29日", "note": "", "verified": true, "effects": {"mind": 7, "passion": 9}}, {"sageId": "nietzsche", "quote": "生きる「なぜ」を持つ者は、ほとんどあらゆる「いかに」に耐えられる。", "quoteOriginal": "He who has a why to live for can bear almost any how.", "source": "ニーチェ『偶像の黄昏』箴言と矢 12, 1889", "note": "", "verified": true, "effects": {"mind": 7, "wisdom": 9}}], "titleEn": "I fail no matter how often I try. I''m broken.", "bodyEn": "I rise and fall, rise and fall again. It doesn''t feel like I''m moving forward.", "tier": "paid"}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','self_mastery_01','paid','{"id": "self_mastery_01", "category": "self", "mood": "lost", "tier": "paid", "title": "目先の誘惑や怠け心に、負けそうになる。", "body": "やるべきことは分かっている。なのに、楽な方へ楽な方へと、心が流れてしまう。", "titleEn": "I keep losing to temptation and laziness.", "bodyEn": "I know what I should do. Yet my heart keeps drifting toward the easy way out.", "advices": [{"sageId": "original", "quote": "意志は、使うほど強くなる筋肉のようなもの。", "quoteEn": "Will is like a muscle — it grows stronger the more you use it.", "note": "", "effects": {"mind": 4}}, {"sageId": "confucius", "quote": "己に克ちて礼に復るを仁と為す。", "quoteOriginal": "克己復礼為仁。", "quoteEn": "To master oneself and return to what is right — that is benevolence.", "source": "論語 顔淵第十二", "note": "自分に打ち克ち、あるべき姿に立ち返ること。", "verified": true, "effects": {"mind": 5, "wisdom": 9}}, {"sageId": "seneca", "quote": "人生が短いのではない。私たちが、多くの時間を浪費しているのだ。", "quoteOriginal": "It is not that we have a short time to live, but that we waste much of it.", "quoteEn": "It is not that we have a short time to live, but that we waste much of it.", "source": "セネカ『人生の短さについて』(De Brevitate Vitae)", "note": "", "verified": true, "effects": {"mind": 4, "wisdom": 8, "passion": 4}}]}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','hardship_meaning_01','paid','{"id": "hardship_meaning_01", "category": "self", "mood": "down", "tier": "paid", "title": "このつらさに、意味なんてあるのか。", "body": "報われない苦しみが続く。耐える意味が、だんだん分からなくなってきた。", "titleEn": "Does this pain even mean anything?", "bodyEn": "Unrewarded suffering drags on. I''m losing sight of why I should keep enduring it.", "advices": [{"sageId": "original", "quote": "意味は、後からわかる。今はただ、生き延びるだけでいい。", "quoteEn": "The meaning comes later. For now, simply surviving is enough.", "note": "", "effects": {"mind": 5}}, {"sageId": "nietzsche", "quote": "私を殺さないものは、私をより強くする。", "quoteOriginal": "What does not kill me makes me stronger.", "quoteEn": "What does not kill me makes me stronger.", "source": "ニーチェ『偶像の黄昏』箴言と矢 8, 1889", "note": "", "verified": true, "effects": {"mind": 7, "wisdom": 8, "passion": 5}}]}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('event','kindness_giving_01','paid','{"id": "kindness_giving_01", "category": "relationship", "mood": "lost", "tier": "paid", "title": "自分に余裕がなくて、人に優しくできない。", "body": "本当は優しくありたい。でも自分のことで精一杯で、誰かを思いやる隙間がない。", "titleEn": "I have no room to spare, so I can''t be kind to others.", "bodyEn": "I truly want to be kind. But I''m so consumed by my own struggles that there''s no room to care for anyone.", "advices": [{"sageId": "original", "quote": "まず自分を満たそう。それはわがままではなく、優しさの源。", "quoteEn": "Fill your own cup first. That is not selfishness — it is the source of kindness.", "note": "", "effects": {"mind": 5, "bonds": 3}}, {"sageId": "annefrank", "quote": "幸せな人は、ほかの人をも幸せにする。", "quoteOriginal": "Whoever is happy will make others happy too.", "quoteEn": "Whoever is happy will make others happy too.", "source": "『アンネの日記』", "note": "", "verified": true, "effects": {"mind": 6, "bonds": 7}}, {"sageId": "scripture_bible", "tradition": "christianity", "quote": "与えなさい。そうすれば、あなたがたにも与えられる。", "quoteOriginal": "Give, and it will be given to you.", "quoteEn": "Give, and it will be given to you.", "source": "新約聖書 ルカによる福音書 6:38", "note": "聖典の言葉として引用。", "verified": true, "rank": 5, "effects": {"mind": 11, "bonds": 9}}]}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('legend','L01','paid','{"id": "L01", "sageId": "socrates", "rarity": "legendary", "minWisdom": 40, "verified": true, "quote": "吟味されざる生に、人にとって生きる値打ちはない。", "quoteOriginal": "The unexamined life is not worth living.", "source": "プラトン『ソクラテスの弁明』38a", "effects": {"wisdom": 14, "mind": 6}}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('legend','L02','paid','{"id": "L02", "sageId": "king", "rarity": "legendary", "minWisdom": 40, "verified": true, "quote": "闇は闇を追い払えない。光だけがそれをなしうる。憎しみは憎しみを追い払えない。愛だけがそれをなしうる。", "quoteOriginal": "Darkness cannot drive out darkness; only light can do that. Hate cannot drive out hate; only love can do that.", "source": "M.L.キング『汝の敵を愛せよ』(Strength to Love), 1963", "effects": {"mind": 10, "bonds": 8, "wisdom": 8}}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('legend','L03','paid','{"id": "L03", "sageId": "mandela", "rarity": "legendary", "minWisdom": 60, "verified": true, "quote": "教育は、世界を変えるために使える最も強力な武器である。", "quoteOriginal": "Education is the most powerful weapon which you can use to change the world.", "source": "ヴィトワーテルスラント大学での演説, 2003", "effects": {"wisdom": 14, "passion": 6}}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('legend','L04','paid','{"id": "L04", "sageId": "shakespeare", "rarity": "legendary", "minWisdom": 60, "verified": true, "quote": "何よりもまず、おのれ自身に忠実であれ。", "quoteOriginal": "This above all: to thine own self be true.", "source": "シェイクスピア『ハムレット』第1幕第3場", "effects": {"wisdom": 10, "mind": 6, "passion": 4}}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('legend','L05','paid','{"id": "L05", "sageId": "laozi", "rarity": "legendary", "minWisdom": 90, "verified": true, "quote": "人を知る者は智なり。自らを知る者は明なり。", "quoteOriginal": "知人者智、自知者明。", "source": "老子『道徳経』第33章", "effects": {"wisdom": 14, "mind": 4}, "quoteEn": "He who knows others is wise; he who knows himself is enlightened."}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('legend','L06','paid','{"id": "L06", "sageId": "einstein", "rarity": "legendary", "minWisdom": 90, "verified": true, "quote": "大切なのは、問い続けることをやめないことだ。好奇心には、それ自体に存在する理由がある。", "quoteOriginal": "The important thing is not to stop questioning. Curiosity has its own reason for existence.", "source": "LIFE誌『Old Man''s Advice to Youth』, 1955年5月2日", "effects": {"wisdom": 12, "passion": 6}}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('legend','L07','paid','{"id": "L07", "sageId": "keller", "rarity": "legendary", "minWisdom": 120, "verified": true, "quote": "一人でできることは、ほんのわずか。けれど、共にあれば、私たちは多くを成せる。", "quoteOriginal": "Alone we can do so little; together we can do so much.", "source": "J.P.ラッシュ『ヘレンと教師』(Helen and Teacher), 1980 に記録", "effects": {"mind": 8, "bonds": 10}}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('legend','L08','paid','{"id": "L08", "sageId": "scripture_dhammapada", "tradition": "buddhism", "rarity": "legendary", "minWisdom": 120, "verified": true, "quote": "心は、すべてに先立つ。心が主であり、すべては心がつくり出す。", "quoteOriginal": "Mind precedes all mental states. Mind is their chief; they are all mind-wrought.", "source": "法句経(ダンマパダ) 第1偈", "note": "聖典の言葉として引用。", "effects": {"mind": 10, "wisdom": 12}}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('legend','L09','paid','{"id": "L09", "sageId": "fukuzawa", "rarity": "legendary", "minWisdom": 160, "verified": true, "quote": "天は人の上に人を造らず、人の下に人を造らず、と云えり。", "quoteOriginal": "天は人の上に人を造らず人の下に人を造らずと云へり。", "source": "福沢諭吉『学問のすゝめ』初編, 1872", "effects": {"wisdom": 12, "bonds": 6}, "quoteEn": "Heaven does not create one person above or below another."}',1781869217);
INSERT OR REPLACE INTO content (type,id,tier,payload,updated_at) VALUES ('legend','L10','paid','{"id": "L10", "sageId": "confucius", "rarity": "legendary", "minWisdom": 160, "verified": true, "quote": "之を知る者は之を好む者に如かず。之を好む者は之を楽しむ者に如かず。", "quoteOriginal": "知之者不如好之者、好之者不如楽之者。", "source": "論語 雍也第六", "note": "知る人は好む人に及ばず、好む人は楽しむ人に及ばない。", "effects": {"wisdom": 10, "passion": 8}, "quoteEn": "Those who know it are not equal to those who love it; those who love it are not equal to those who delight in it."}',1781869217);
